import style from "./index.module.scss"
import template from './index.html'

class Routes extends HTMLElement {
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    shadowRoot.innerHTML = template
  }
  static get observedAttributes() {
    return [];
  }
  attributeChangedCallback(name, oldValue, newValue) {
    // this.render()
  }

  willLoad = () => {
    window.addEventListener("popstate", this.render);
  }
  connectedCallback() {
    setTimeout(() => {
      this.willLoad()
      this.render()
    })
  }

  disconnectedCallback() {
    window.removeEventListener("popstate", this.render);
  }

  render = async () => {
    const hash = window.location.hash
    const routeList = Array.from(this.children)
    routeList.forEach(async route => {
      let containChild = false
      if (route.hasAttribute("children")) {
        const children = route.getAttribute("children") 
        containChild = JSON.parse(children).includes(hash)
      }
      if (containChild || route.getAttribute("route") === hash) {
        const isAttached = route.contains(route.getElement())
        if (isAttached) {
          route.setActive()
        } else {
          await route.render()
        }
      } else {
        route.dispose()
      }
    })
  }

}

customElements.define('huanlin-routes', Routes);