import style from "./index.module.scss"
import template from './index.html'
import { loadMap } from "../../utils/lazyLoad"

class Route extends HTMLElement {
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    shadowRoot.innerHTML = template
  }
  set route(value) {
  }
  get route() {
    return this.getAttribute("route") || ""
  }
  static get observedAttributes() {
    return ['element', 'route'];
  }
  attributeChangedCallback(name, oldValue, newValue) {
  }

  willLoad = () => {
    this.rootEle = this.shadowRoot?.querySelector(".root")
  }
  connectedCallback() {
    this.willLoad()
  }
  disconnectedCallback() {
    this.element?.remove()
  }

  initElement = async ({tag, active = false, element}) => {
    if (!tag) return
    if (await this.defineElement(tag)) {
      if (active) {
        this.element = document.createElement(tag)
        this.appendChild(this.element)
      }
      await customElements.whenDefined(tag)
      const set = this.getUndefinedElementSet(element || this.element)
      return Promise.all(Array.from(set).map(async ele => await this.initElement({tag: ele.localName, element: ele})))
    } else {
      if (active) {
        this.element = document.createElement(tag)
        this.appendChild(this.element)
      }
    }
  }

  getUndefinedElementSet = ele => {
    const lightDomEleList = Array.from(ele.querySelectorAll(":not(:defined)")).map(ele => ele)
    let shadowDomEleList = []
    if (ele.shadowRoot) {
      shadowDomEleList = Array.from(ele.shadowRoot.querySelectorAll(":not(:defined)")).map(ele => ele)
    }
    return new Set([...lightDomEleList, ...shadowDomEleList])
  }

  defineElement = async (tag) => {
    if (customElements.get(tag) === undefined && loadMap[tag]) {
      const Instance = await loadMap[tag]()
      !customElements.get(tag) && customElements.define(tag, Instance.default);
      return await customElements.whenDefined(tag);
    } 
    return false
  }

  render = async () => {
    this.setActive()
    await this.initElement({tag: this.getAttribute("element"), active: true})
  }
  getElement = () => {
    return this.element
  }
  setActive = () => {
    this.setAttribute("active", "")
  }
  dispose = () => {
    this.removeAttribute("active")
    this.element?.remove()

  }
}

customElements.define('huanlin-route', Route);