import style from "./index.module.scss"
import template from './index.html'

class Suspense extends HTMLElement {
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    shadowRoot.innerHTML = template
  }
  willLoad = () => {
    this.defaultSlot = this.shadowRoot?.querySelector("slot:not([name='fallback'])")
    this.fallbackSlot = this.shadowRoot?.querySelector("slot[name='fallback']")
    this.defaultSlot.assignedElements().forEach(ele => {
      customElements.whenDefined(ele.localName).then(() => {
        this.fallbackSlot.assignedElements().forEach(fe => {
          fe.remove()
        })
      })
    })
  }
  connectedCallback() {
    this.willLoad()
    this.render()
  }
  disconnectedCallback() {
  }

  render = () => {
  }
}

customElements.define('huanlin-suspense', Suspense);